const queueVisible = signal(true, { key: "queueVisible" })
const selectedStoryId = signal('alpha', { key: "selectedStoryId" })
const hostNoteFilter = signal('', { key: "hostNoteFilter" })

function boardSummary() {
  return `${stories().length} posts create real scroll depth while the selected card proves target-specific build output.`
}

function queueMeta() {
  return queueVisible()
    ? `${stories().length} posts ready`
    : 'Feed collapsed'
}

function toggleQueue() {
  queueVisible.set(!queueVisible())
}

function selectStory(id) {
  selectedStoryId.set(id)
}

function selectedStory() {
  return stories().find((story) => story.id === selectedStoryId()) || stories()[0]
}

function selectedSummary() {
  const story = selectedStory()
  return story ? `${story.hostLabel} selected` : 'No feed post selected'
}

function selectedHostNote() {
  const story = selectedStory()
  return story ? story.hostNote : ''
}

function readEventTextValue(event) {
  if (event && typeof event.value === 'string') {
    return event.value
  }

  if (event && typeof event.text === 'string') {
    return event.text
  }

  if (event && event.target && typeof event.target.value === 'string') {
    return event.target.value
  }

  return ''
}

function normalizedHostNoteFilter() {
  return hostNoteFilter().trim().toLowerCase()
}

function updateHostNoteFilter(event) {
  hostNoteFilter.set(readEventTextValue(event))
}

function hasSelectedHostNote() {
  return selectedHostNote().length > 0
}

function hostNoteFilterSummary() {
  const filter = hostNoteFilter().trim()
  return filter.length > 0
    ? `Filtering feed note by "${filter}".`
    : 'Feed note filter inactive.'
}

function showsSelectedHostNote() {
  const note = selectedHostNote()
  if (!note.length) {
    return false
  }

  const filter = normalizedHostNoteFilter()
  return filter.length === 0 || note.toLowerCase().includes(filter)
}

function filteredHostNoteSummary() {
  const filter = hostNoteFilter().trim()
  return filter.length > 0
    ? `Current feed note is hidden until it matches "${filter}".`
    : ''
}

function promoteSelected() {
  const currentId = selectedStoryId()

  stories.update((list) => {
    const index = list.findIndex((story) => story.id === currentId)

    if (index <= 0) {
      return list
    }

    const selected = list[index]
    return [selected, ...list.slice(0, index), ...list.slice(index + 1)]
  })
}

function rotateQueue() {
  stories.update((list) => {
    if (list.length < 2) {
      return list
    }

    return [...list.slice(1), list[0]]
  })
}

function storyCardClass(story) {
  return story.id === selectedStoryId()
    ? 'proof-state-board__post proof-state-board__post--active'
    : 'proof-state-board__post'
}
  return { stories, queueVisible, selectedStoryId, hostNoteFilter, boardSummary, queueMeta, toggleQueue, selectStory, selectedStory, selectedSummary, selectedHostNote, readEventTextValue, normalizedHostNoteFilter, updateHostNoteFilter, hasSelectedHostNote, hostNoteFilterSummary, showsSelectedHostNote, filteredHostNoteSummary, promoteSelected, rotateQueue, storyCardClass };
}
